import { safeExportSelfTest } from '../shared/safe-export.js';
const T=window.GHRAB;
await T.accessReady;
if(T.isAdmin()){
  const box=document.querySelector('#test-results');
  const run=document.querySelector('#run-tests');
  const summary=document.querySelector('#diagnostic-summary');
  function card(label,status,detail){const article=document.createElement('article');article.className=`test-card ${status}`;const mark=document.createElement('span');mark.textContent=status==='ok'?'✓':status==='pending'?'…':'!';const h=document.createElement('h2');h.textContent=label;const p=document.createElement('p');p.textContent=detail;article.append(mark,h,p);return article}
  async function imageOk(src){return new Promise(resolve=>{const image=new Image();image.onload=()=>resolve(true);image.onerror=()=>resolve(false);image.src=`${src}${src.includes('?')?'&':'?'}qa=${Date.now()}`})}
  async function fetchOk(url){try{const response=await fetch(url,{cache:'no-store'});return response.ok}catch{return false}}
  function storageCheck(){const key='ghrab.selftest';const value=`ok-${Date.now()}`;const written=T.safeSetItem(key,value,{silent:true});const read=T.safeGetItem(key)===value;T.safeRemoveItem(key);return written&&read}
  function validHandoff(){const material={schema:'ghrab-material-v1',id:'selftest-material',version:1,title:'Selftest',subject:'QA',yearGroup:'',level:'',language:'cs',objectives:['Ověřit přenos'],content:{sourceText:'Testovací obsah bez osobních údajů.',vocabulary:[],tasks:[]},differentiation:{variants:[]},quality:{status:'teacher-reviewed',reviewedAt:new Date().toISOString()},provenance:{containsPersonalData:false}};const created=T.createHandoff('generator',material);const ok=Boolean(created)&&T.readHandoff()?.material?.id===material.id;T.clearHandoff();return ok}
  function renderSummary(results){const passed=results.filter(item=>item.status==='ok').length;const failed=results.filter(item=>item.status==='fail').length;summary.replaceChildren();const a=document.createElement('span');a.className='chip';a.textContent=T.t(`${passed} kontrol v pořádku`,`${passed} checks passed`);const b=document.createElement('span');b.className='chip';b.textContent=failed?T.t(`${failed} problémů`,`${failed} issues`):T.t('Bez zjištěné chyby','No detected error');summary.append(a,b)}
  async function runChecks(){
    run.disabled=true;run.textContent=T.t('Kontroluji…','Checking…');box.replaceChildren(card(T.t('Probíhá kontrola','Check in progress'),'pending',T.t('Načítám konfiguraci a ověřuji lokální funkce.','Loading configuration and verifying local functions.')));
    const results=[];
    try{const apps=await T.loadApps();results.push({label:T.t('Registr aplikací','Application registry'),status:Array.isArray(apps)&&apps.length>=4?'ok':'fail',detail:T.t(`${apps.length} aplikace načteny.`,`${apps.length} applications loaded.`)});const icons=await Promise.all(apps.map(app=>imageOk(`../${app.icon}`)));results.push({label:T.t('Ikony aplikací','Application icons'),status:icons.every(Boolean)?'ok':'fail',detail:T.t(`${icons.filter(Boolean).length}/${icons.length} ikon je dostupných.`,`${icons.filter(Boolean).length}/${icons.length} icons are available.`)})}catch(error){results.push({label:T.t('Registr aplikací','Application registry'),status:'fail',detail:error.message})}
    const access=T.getAccessSnapshot();results.push({label:T.t('Podepsaný správcovský přístup','Signed administrator access'),status:access.valid&&T.isAdmin()?'ok':'fail',detail:access.valid?T.t(`Platný přístup: ${access.permit.jti}.`,`Valid permit: ${access.permit.jti}.`):T.formatReason(access.reason,T.state.language)});
    try{const [policy,key,revocations]=await Promise.all(['../config/access-policy.json','../config/access-public-key.json','../config/revoked-access.json'].map(url=>fetch(url,{cache:'no-store'}).then(r=>{if(!r.ok)throw new Error(String(r.status));return r.json()})));const ok=policy.schema==='ghrab-access-policy-v1'&&key.schema==='ghrab-access-public-key-v1'&&revocations.schema==='ghrab-access-revocation-list-v1';results.push({label:T.t('Konfigurace oprávnění','Access configuration'),status:ok?'ok':'fail',detail:T.t(`${Object.keys(policy.applications||{}).length} aplikace · klíč ${key.keyId}.`,`${Object.keys(policy.applications||{}).length} applications · key ${key.keyId}.`)})}catch(error){results.push({label:T.t('Konfigurace oprávnění','Access configuration'),status:'fail',detail:error.message})}
    const storage=storageCheck();results.push({label:T.t('Místní úložiště','Local storage'),status:storage?'ok':'fail',detail:storage?T.t('Bezpečné čtení, zápis a odstranění fungují.','Safe read, write and removal work.'):T.t('Prohlížeč blokuje místní úložiště.','The browser blocks local storage.')});
    try{results.push({label:T.t('Předání materiálu','Material handoff'),status:validHandoff()?'ok':'fail',detail:T.t('Krátkodobý přenos platného GHRAB Material v1 funguje.','Short-term transfer of a valid GHRAB Material v1 package works.')})}catch(error){results.push({label:T.t('Předání materiálu','Material handoff'),status:'fail',detail:error.message})}
    const invalid=T.validateMaterialPackage({schema:'ghrab-material-v1'});results.push({label:T.t('Hloubková validace importu','Deep import validation'),status:invalid.valid===false&&invalid.errors.length>=3?'ok':'fail',detail:T.t(`Neplatný testovací soubor zachytil ${invalid.errors.length} problémů.`,`The invalid test file produced ${invalid.errors.length} validation issues.`)});
    results.push({label:T.t('Bezpečný anonymní export','Safe anonymous export'),status:safeExportSelfTest()?'ok':'fail',detail:T.t('Skutečné exportní transformace nepropustily záměrně vložená citlivá data.','Real export transformations did not leak intentionally inserted sensitive data.')});
    const pages=['../','../access/','../workflow/','../library/','../safety/'];const pageChecks=await Promise.all(pages.map(fetchOk));results.push({label:T.t('Klíčové stránky portálu','Core portal pages'),status:pageChecks.every(Boolean)?'ok':'fail',detail:T.t(`${pageChecks.filter(Boolean).length}/${pageChecks.length} stránek odpovědělo úspěšně.`,`${pageChecks.filter(Boolean).length}/${pageChecks.length} pages responded successfully.`)});
    const guardChecks=await Promise.all(['../access/app-guard.js','../access/access-gate.css','../integration/README.md'].map(fetchOk));results.push({label:T.t('Ochrana dílčích aplikací','Individual app protection'),status:guardChecks.every(Boolean)?'ok':'fail',detail:T.t(`${guardChecks.filter(Boolean).length}/${guardChecks.length} integračních souborů je dostupných.`,`${guardChecks.filter(Boolean).length}/${guardChecks.length} integration files are available.`)});
    const worker='serviceWorker'in navigator;results.push({label:T.t('PWA prostředí','PWA environment'),status:worker?'ok':'fail',detail:worker?T.t('Prohlížeč podporuje service worker.','The browser supports service workers.'):T.t('Tento prohlížeč service worker nepodporuje.','This browser does not support service workers.')});
    const usage=T.storageUsage();results.push({label:T.t('Velikost místních dat','Local data size'),status:Number.isFinite(usage.bytes)?'ok':'fail',detail:T.t(`Studio používá přibližně ${usage.kilobytes} kB místního úložiště.`,`The Studio uses approximately ${usage.kilobytes} kB of local storage.`)});
    box.replaceChildren(...results.map(item=>card(item.label,item.status,item.detail)));renderSummary(results);run.disabled=false;run.textContent=T.t('Spustit úplnou kontrolu','Run full check');
  }
  run.addEventListener('click',runChecks);document.addEventListener('ghrab:language',runChecks);runChecks();
}
